import { isString, isNumber, isBoolean, isArray, isObject, isNil, isEmpty } from '../src/typeGuards'

let failures = 0
async function check(name: string, got: unknown, want: unknown) {
  got = await got  // resolve promises transparently
  const ok = JSON.stringify(got) === JSON.stringify(want)
  console.log(`  ${ok ? 'PASS' : 'FAIL'} — ${name}`)
  if (!ok) {
    console.log(`       got:  ${JSON.stringify(got)}`)
    console.log(`       want: ${JSON.stringify(want)}`)
    failures++
  }
}

;(async () => {
await check("isString true", isString("hello"), true)
await check("isString false", isString(42), false)
await check("isNumber true", isNumber(42), true)
await check("isNumber NaN", isNumber(NaN), false)
await check("isArray true", isArray([1,2,3]), true)
await check("isArray false obj", isArray({length:3}), false)
await check("isObject true", isObject({a:1}), true)
await check("isObject false arr", isObject([1,2]), false)
await check("isObject false null", isObject(null), false)
await check("isNil null", isNil(null), true)
await check("isNil undefined", isNil(undefined), true)
await check("isNil 0", isNil(0), false)
await check("isEmpty empty str", isEmpty(""), true)
await check("isEmpty empty arr", isEmpty([]), true)
await check("isEmpty empty obj", isEmpty({}), true)
await check("isEmpty non-empty", isEmpty("hi"), false)
await check("isEmpty null", isEmpty(null), true)
console.log(failures === 0 ? 'ALL PASS' : `${failures} FAILURE(S)`)
process.exit(failures === 0 ? 0 : 1)
})()
